import { tokenizeNative, parseStylesheetNative, serializeNative } from "./native/css.bind.js";

export function tokenizeCss(input) {
  return tokenizeNative(input);
}

export function parseCss(input) {
  return parseStylesheetNative(input);
}

export function serializeCss(node) {
  return serializeNative(node, undefined);
}

export function serializeCssWithOptions(node, options) {
  return serializeNative(node, options);
}
